  ('aboriginal-6f0ba476-moex-00171', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '有關營利事業受控外國企業（簡稱營利事業CFC）制度之說明，下列何者錯誤？', '["營利事業CFC制度於112年開始實施", "營利事業及其關係人對該關係企業具有重大影響力之外國企業為CFC", "CFC 於所在國家或地區有實質營運活動，倘該公司當年度經股東同意或股東會決議不分配盈 餘時，得免列投資收益", "CFC 當年度之盈餘在一定基準以上，營利事業應按其持有股份或資本額之比率及持有期間計 算，認列投資收益，計入當年度所得額課稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00172', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依所得稅法相關規定，營利事業對下列何者之捐贈有金額限制？①經政府登記有案之體育團體', '["公益慈善團體", "公立大學", "文化創意事業成立育成中心", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00173', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', 'A公司於113年3月30日經主管機關核准解散，於113年8月30日辦理清算完畢，清算所得為 15萬元。A公司應辦理清算申報之期限為清算結束之日起幾日內？應納稅額多少？', '["30日、3萬元", "45日、3萬元", "30日、1.5萬元", "45日、1.5萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00174', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依所得稅法之規定，下列個人所得分類與課稅之敘述何者錯誤？①個人領取之資遣費屬退職所得', '["個人辦理補習班之收入屬營利所得", "與銀行從事結構性商品交易所得屬營利所得", "取自 營利事業受贈之財產屬免稅所得  ⑤個人作品自行出版銷售著作之收入屬執行業務所得", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00175', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依現行房地合一制之規定，下列敘述何者正確？', '["營利事業交易其興建房屋完成後第一次移轉之房屋、土地交易所得，採併計營利事業所得額結 算申報納稅", "個人未提示因取得、改良及移轉而支付之費用者，稽徵機關得按成交價格3%計算其費用，並以 50萬元為限", "個人交易因繼承取得之房屋、土地，該筆房屋、土地係被繼承人於105年12月31日取得，房 地交易所得應併入綜合所得總額課稅", "總機構在中華民國境外之營利事業，持有房屋、土地之期間超過5年者，稅率為20%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00176', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '外國A公司在我國境內設有分公司，且有轉投資國內甲公司（上市公司）而獲配之股利所得，該 筆股利所得的課稅方式為何？', '["計入A公司境內之分公司的課稅所得，結算申報完稅", "由甲公司於給付股利所得時，按給付額扣取21%", "由境內分公司按次申報納稅", "屬免稅所得，無須課稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00177', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '小規模營業人，經稽徵機關查定每月營業額為180,000元，當期有捐贈公益團體之進項稅額2,000 元，依加值型及非加值型營業稅法規定，其當期應納營業稅額為若干元？', '["5,400元", "5,200元", "4,800元", "3,400元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00178', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '某外國技藝表演業於113年5月於臺中國家歌劇院演出3日，其營業稅應如何申報？', '["應於演出結束後15日內向臺北市國稅局報繳", "應於演出結束後15日內向臺中市地方稅務局報繳", "應於演出結束後15日內向中區國稅局報繳", "免報繳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00179', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依加值型及非加值型營業稅法之規定，有關營業稅之課徵，下列敘述何者錯誤？', '["營業人以其產製供銷售之貨物，轉供營業人本業及附屬業務使用之固定資產，除設帳記載外， 可免開立統一發票", "營業人購買載運員工上、下班用之大型客車，其進項稅額得扣抵銷項稅額", "營業人當期無銷售額者，得併同次期有銷售額時再申報營業稅", "按加值型營業稅計稅之營業人購買國外勞務，專供經營應稅貨物或勞務使用者，免課徵進口營 業稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
